module sr_latch (
    input wire AntiIntuitive_S,
    input wire R,
    output reg Q,
    output wire Qn
);
    assign Qn = ~Q;

    always @(AntiIntuitive_S, R) begin
        if (AntiIntuitive_S && !R) 
            Q <= 1; // Set
        else if (!AntiIntuitive_S && R) 
            Q <= 0; // Reset
        // If both AntiIntuitive_S and R are 0, maintain the previous state (Q)
        // If both AntiIntuitive_S and R are 1, the state is undefined, so we do nothing.
    end
endmodule
